export const BALI_SITES: DiveSite[] = [
  { slug:'usat-liberty-wreck',name:'USAT Liberty Wreck',area:'Tulamben',areaSlug:'tulamben',rank:1,type:'Wreck',access:'Shore',minDepth:5,maxDepth:30,avgDepth:18,visibility:'15–25m',temp:'27–29°C',current:'Mild — surge possible near bow',difficulty:'All levels',minCert:'Open Water',bestTime:'Dawn (5:15–5:30am) for bumpheads & best visibility',bestSeason:'Apr–Nov',goodFor:['Wreck diving','Night diving','All levels','Macro photography','Bumphead parrotfish'],facilities:['Dive centres in Tulamben village','Shore access — porters carry tanks','Equipment rental','Accommodation nearby'],lat:-8.2809,lng:115.6029,rating:4.9,reviews:312,description:'One of the most accessible and celebrated wreck dives in the world. The 120m USAT Liberty (US Army Transport) was torpedoed by Japanese submarine I-166 in 1942 and rolled off Tulamben beach by the 1963 Mount Agung eruption. She now lies on her starboard side on a black volcanic sand slope, just 30m from shore. The stern sits at 5m and the bow at 30m. Encrusted in dense soft and hard coral with one of the densest fish populations of any wreck on earth — a true living reef. Dive at dawn for bumphead parrotfish and fewer crowds.',marineLife:[{name:'Bumphead parrotfish',frequency:'common'},{name:'Schooling jackfish',frequency:'very common'},{name:'Reef sharks',frequency:'occasional'},{name:'Giant grouper',frequency:'common'},{name:'Pygmy seahorse',frequency:'rare'},{name:'Hawksbill turtle',frequency:'occasional'}],safetyNotes:['Shore entry over smooth volcanic pebbles — go slowly with gear','Surge near bow in swell','Boat traffic offshore — ascend on the wreck, deploy SMB at surface','Do not push into tight swim-throughs — wreck is collapsing in places'],briefing:'Shore entry from Tulamben black pebble beach. Local porters carry tanks to waterline. Wade in, lean back, descend on sandy slope to stern at 5m. Swim north along the wreck — upper deck, midship break, engine room, bow. Return via wreck or sand. Safety stop at 5m on the wreck shallow section.',emergencyContact:'BIMC Hospital Tulamben / Kuta: +62 361 761263',diagramType:'wreck' },
  { slug:'manta-point',name:'Manta Point',area:'Nusa Penida',areaSlug:'nusa-penida',rank:2,type:'Reef',access:'Boat',minDepth:8,maxDepth:40,avgDepth:14,visibility:'10–25m',temp:'24–27°C',current:'Moderate to strong — surge from south coast',difficulty:'Intermediate',minCert:'Advanced Open Water',bestTime:'Early morning — calmer conditions',bestSeason:'Year round — most reliable Apr–Oct',goodFor:['Manta rays','Photography','Marine life'],facilities:['Boat only — 45 min from Sanur or Toyapakeh','Dive operators in Nusa Penida and Padang Bai'],lat:-8.7761,lng:115.4734,rating:4.9,reviews:198,description:'One of the most reliable manta ray encounters in Bali. Located on the exposed southwest coast of Nusa Penida, Manta Point has three primary manta cleaning stations at 8–12m where reef mantas gather year-round to be cleaned by wrasse. The site faces the Indian Ocean and can be affected by south swell, making it an exposed dive that needs good conditions. In addition to mantas, the site hosts stingrays, turtles, sharks, and abundant reef life. Mola Mola appear here in season.',marineLife:[{name:'Reef manta ray',frequency:'very common'},{name:'Blue-spotted stingray',frequency:'common'},{name:'Hawksbill turtle',frequency:'common'},{name:'Reef sharks',frequency:'occasional'},{name:'Mola mola',frequency:'seasonal'}],safetyNotes:['Exposed to south swell — dive only in good conditions','Strong surge possible at cleaning stations','Do not touch or chase mantas — never position above them','Site can be cancelled if seas are rough'],briefing:'Boat entry only — 45 min from Sanur or Toyapakeh. Descend to cleaning station rocks at 8–12m. Hover low, remain still. Mantas will pass above and around you. Do not chase. Three main cleaning stations. Ascend on guide signal. SMB pick-up by boat.',emergencyContact:'Nusa Penida Health Clinic: +62 366 5598001 | BIMC Kuta: +62 361 761263',diagramType:'boat' },
  { slug:'crystal-bay',name:'Crystal Bay',area:'Nusa Penida',areaSlug:'nusa-penida',rank:3,type:'Reef',access:'Boat',minDepth:5,maxDepth:40,avgDepth:25,visibility:'20–40m',temp:'20–27°C',current:'Strong — dangerous downcurrent possible',difficulty:'Advanced',minCert:'Advanced Open Water',bestTime:'Early morning — before current builds',bestSeason:'Jul–Oct for Mola Mola',goodFor:['Mola mola','Deep diving','Experienced divers','Photography'],facilities:['Boat only','Dive operators in Nusa Penida'],lat:-8.7208,lng:115.5092,rating:4.8,reviews:156,description:'Crystal Bay is the premier Mola Mola (ocean sunfish) dive site in Bali and one of the most famous in the world. The bay features two coral reef formations separated by a sandy slope, with the topography dropping to 50m+ at a large cleaning station rock where Mola Mola surface during cold upwellings. The site also hosts mantas, whale sharks, giant trevally, barracuda, and the occasional great white. Outside Mola Mola season it remains a spectacular reef dive. The site is notorious for sudden strong downcurrents — all divers must be experienced.',marineLife:[{name:'Mola mola (ocean sunfish)',frequency:'seasonal (Jul–Oct)'},{name:'Reef manta ray',frequency:'occasional'},{name:'Barracuda',frequency:'common'},{name:'Giant trevally',frequency:'common'},{name:'Reef sharks',frequency:'occasional'},{name:'Wobbegong shark',frequency:'occasional'}],safetyNotes:['Sudden violent downcurrent possible — stay close to reef','Cold thermocline at 18–22m — be prepared','Advanced divers only during Mola season','Crowds in peak season — follow guide strictly'],briefing:'Boat entry on calm north side of bay. Descend quickly keeping reef in view. Navigate around the bay — shallow plateau 5–12m then wall/slope to Mola cleaning station at 25–35m. Strict NDL and depth management. Ascend on reef with guide. Safety stop at 5m. SMB pick-up.',emergencyContact:'Nusa Penida Health Clinic: +62 366 5598001 | BIMC Kuta: +62 361 761263',diagramType:'boat' },
  { slug:'tulamben-drop-off',name:'Tulamben Drop Off',area:'Tulamben',areaSlug:'tulamben',rank:4,type:'Wall',access:'Shore',minDepth:3,maxDepth:40,avgDepth:20,visibility:'10–30m',temp:'26–29°C',current:'Mild — can increase at outer spurs near full moon',difficulty:'All levels',minCert:'Open Water',bestTime:'Morning — best visibility',bestSeason:'Apr–Nov',goodFor:['Wall diving','Marine life','Photography','All levels','Macro'],facilities:['Shore access at temple below cliff','Dive centres in Tulamben'],lat:-8.2742,lng:115.5975,rating:4.7,reviews:89,description:'Also known as the Tulamben Wall, the Drop Off was formed by the same 1963 Mount Agung lava flow that pushed the Liberty into the sea. Three coral spurs (fingers) drop from 3m to over 80m on the west-facing wall. The site is blanketed in fire coral, sea fans, and sponges, with a signature giant purple gorgonian at 29m. The mix of sandy slope for macro and sheer wall for big-fish encounters makes this Tulamben\'s most versatile dive site.',marineLife:[{name:'Sea fans & gorgonians',frequency:'very common'},{name:'Pygmy seahorse',frequency:'occasional'},{name:'Ghost pipefish',frequency:'occasional'},{name:'Frogfish',frequency:'occasional'},{name:'Bumphead parrotfish',frequency:'occasional'},{name:'Reef sharks',frequency:'occasional'}],safetyNotes:['Wall drops past 80m — stay within planned depth','Tempting to go deep — very clear water is deceptive','If current runs east away from bay, turn back early to avoid fighting it home','Fire coral throughout — do not touch'],briefing:'Shore entry at beach below temple. Head out on sandy slope, reef to your right. Pass two large barrel sponges at 12m and 15m — wall begins. Descend along wall to planned max depth (30m recommended). Turn right 90° and gradually ascend parallel to shore. Return along slope for safety stop. Exit at beach.',emergencyContact:'BIMC Hospital Kuta: +62 361 761263',diagramType:'wall' },
  { slug:'blue-lagoon',name:'Blue Lagoon',area:'Padang Bai',areaSlug:'padang-bai',rank:5,type:'Reef',access:'Shore',minDepth:2,maxDepth:15,avgDepth:8,visibility:'10–20m',temp:'27–29°C',current:'Mild — current free most days',difficulty:'Beginner',minCert:'Open Water',bestTime:'Morning',bestSeason:'Year round',goodFor:['Beginners','Snorkelling','Training','Open Water courses','Families'],facilities:['Shore access from Blue Lagoon beach','Dive centres in Padang Bai'],lat:-8.5328,lng:115.5089,rating:4.4,reviews:74,description:'A calm, sheltered bay in Padang Bai perfect for beginners and Open Water training. The sandy slope leads to healthy coral gardens hosting lionfish, octopus, moray eels, and hundreds of reef fish species. One of the safest and most accessible dives on Bali\'s east coast.',marineLife:[{name:'Lionfish',frequency:'common'},{name:'Octopus',frequency:'common'},{name:'Moray eel',frequency:'common'},{name:'Juvenile reef fish',frequency:'very common'},{name:'Blue-spotted stingray',frequency:'common'}],safetyNotes:['Watch for longtail and ferry boat traffic near bay entrance','Stay within the sheltered bay','Keep students together on training dives'],briefing:'Shore entry from Blue Lagoon beach. Descend on sandy slope to reef at 5–12m. Follow the coral garden. Return along the sand. Safety stop at 5m. Exit at beach.',emergencyContact:'BIMC Hospital Kuta: +62 361 761263',diagramType:'shore' },
  { slug:'sd-point',name:'SD Point',area:'Nusa Penida',areaSlug:'nusa-penida',rank:6,type:'Reef',access:'Boat',minDepth:5,maxDepth:30,avgDepth:18,visibility:'15–30m',temp:'24–28°C',current:'Moderate — uniform drift direction, good for drift diving',difficulty:'Intermediate',minCert:'Advanced Open Water',bestTime:'Morning',bestSeason:'Apr–Oct',goodFor:['Drift diving','Marine life','Reef diving','Photography'],facilities:['Boat only'],lat:-8.7284,lng:115.4898,rating:4.5,reviews:62,description:'Named after the primary school (Sekolah Dasar) on the Nusa Penida shore. SD Point stretches along the north coast with a healthy coral slope and consistent current flowing in one direction — ideal for drift diving. Large queen angelfish, puffer fish, bumphead parrotfish, cuttlefish, and occasional Mola Mola make this one of Penida\'s most rewarding drifts. The reef extends as far as the Toyapakeh jetty to the west.',marineLife:[{name:'Bumphead parrotfish',frequency:'occasional'},{name:'Queen angelfish',frequency:'common'},{name:'Cuttlefish',frequency:'common'},{name:'Whitetip reef shark',frequency:'occasional'},{name:'Mola mola',frequency:'seasonal'}],safetyNotes:['Current always flowing — experienced drift divers only','SMB mandatory for boat pick-up','Water temperature can drop suddenly'],briefing:'Boat drop upstream. Descend to 15–25m on coral slope. Drift with current along the reef — coast to your right. Coral heads for shelter. Signal boat with SMB when ascending. Surface pick-up.',emergencyContact:'Nusa Penida Health Clinic: +62 366 5598001 | BIMC Kuta: +62 361 761263',diagramType:'boat' },
  { slug:'manta-bay',name:'Manta Bay',area:'Nusa Penida',areaSlug:'nusa-penida',rank:7,type:'Reef',access:'Boat',minDepth:5,maxDepth:30,avgDepth:10,visibility:'10–20m',temp:'24–27°C',current:'Mild to moderate',difficulty:'Beginner to Intermediate',minCert:'Open Water',bestTime:'Morning',bestSeason:'Year round',goodFor:['Manta rays','Photography','Beginners','Snorkelling'],facilities:['Boat only — closer to Lembongan than Manta Point'],lat:-8.7844,lng:115.4612,rating:4.6,reviews:103,description:'Manta Bay near Broken Beach on the southwest coast of Nusa Penida attracts reef mantas year-round with high plankton concentrations. The sandy bottom slopes from 5m to 30m with mantas often feeding or resting at 1–6m — sometimes visible from the surface. Calmer and closer than Manta Point, though manta encounters can be less reliable. Wobbegong sharks and spinner dolphins also seen near the adjacent reef.',marineLife:[{name:'Reef manta ray',frequency:'very common'},{name:'Wobbegong shark',frequency:'occasional'},{name:'Blue-spotted stingray',frequency:'common'},{name:'Eagle ray',frequency:'occasional'}],safetyNotes:['Can get crowded with snorkel tours — be patient','No touching mantas','Current can strengthen suddenly'],briefing:'Boat entry. Sandy bottom 5–12m then deeper slope. Mantas often visible from 1–6m — descend slowly to not startle them. Hover below and watch. Guide signals ascent. SMB pick-up.',emergencyContact:'Nusa Penida Health Clinic: +62 366 5598001',diagramType:'boat' },
  { slug:'gamat-bay',name:'Gamat Bay',area:'Nusa Penida',areaSlug:'nusa-penida',rank:8,type:'Reef',access:'Boat',minDepth:5,maxDepth:20,avgDepth:12,visibility:'15–25m',temp:'25–28°C',current:'Mild — protected bay',difficulty:'Beginner',minCert:'Open Water',bestTime:'Morning',bestSeason:'Apr–Oct',goodFor:['Beginners','Macro photography','Snorkelling','Marine life'],facilities:['Boat only'],lat:-8.7214,lng:115.5301,rating:4.4,reviews:45,description:'A protected bay between Crystal Bay and Toyapakeh with a white sandy bottom covered in coral patches and bommies. Crystal clear water and negligible current make Gamat Bay perfect for beginners, photographers, and snorkellers. Excellent macro life with nudibranchs, ghost pipefish, and octopus.',marineLife:[{name:'Nudibranch',frequency:'very common'},{name:'Ghost pipefish',frequency:'occasional'},{name:'Octopus',frequency:'common'},{name:'Moray eel',frequency:'common'},{name:'Reef fish',frequency:'very common'}],safetyNotes:['Boat traffic at bay entrance','Stay with group — deeper water outside bay'],briefing:'Boat entry. Sandy bottom with coral bommies 5–18m. Slow paced dive — look carefully at every structure. Return to boat on guide signal.',emergencyContact:'Nusa Penida Health Clinic: +62 366 5598001',diagramType:'boat' },
  { slug:'toyapakeh-wall',name:'Toyapakeh',area:'Nusa Penida',areaSlug:'nusa-penida',rank:9,type:'Wall',access:'Boat',minDepth:6,maxDepth:30,avgDepth:18,visibility:'20–30m',temp:'24–28°C',current:'Strong — channel current',difficulty:'Intermediate to Advanced',minCert:'Advanced Open Water',bestTime:'Slack tide',bestSeason:'Apr–Oct',goodFor:['Drift diving','Wall diving','Coral gardens','Experienced divers'],facilities:['Boat only — Toyapakeh harbour nearby'],lat:-8.6961,lng:115.4539,rating:4.7,reviews:58,description:'Toyapakeh sits at the entrance to the Ceningan Channel between Nusa Penida and Nusa Lembongan. The channel funnels strong currents past a shallow coral plateau at 6–15m full of diverse tropical marine life, descending to deeper sections to 30m with potential Mola Mola sightings. One of Nusa Penida\'s finest coral gardens — blooming with health due to constant nutrient flow.',marineLife:[{name:'Sea fans',frequency:'very common'},{name:'Schooling fish',frequency:'very common'},{name:'Napoleon wrasse',frequency:'occasional'},{name:'Mola mola',frequency:'seasonal'},{name:'Reef sharks',frequency:'occasional'}],safetyNotes:['Strong and sometimes unpredictable current','Dive at slack tide if possible','SMB mandatory — drift dive pick-up'],briefing:'Boat entry upstream. Descend to coral plateau at 10–15m. Drift through the channel with current. Deeper wall on one side. Ascend on guide signal — deploy SMB for boat pick-up.',emergencyContact:'Nusa Penida Health Clinic: +62 366 5598001',diagramType:'boat' },
  { slug:'batu-belah',name:'Batu Belah',area:'Candidasa',areaSlug:'candidasa',rank:10,type:'Reef',access:'Boat',minDepth:5,maxDepth:25,avgDepth:15,visibility:'10–20m',temp:'26–28°C',current:'Moderate',difficulty:'Intermediate',minCert:'Open Water',bestTime:'Morning',bestSeason:'Apr–Nov',goodFor:['Marine life','Reef diving','Reef sharks'],facilities:['Dive centres in Candidasa','Boat'],lat:-8.5041,lng:115.5712,rating:4.3,reviews:41,description:'A cluster of submerged rocks off Candidasa hosting dense fish populations and good coral coverage. Reliable reef shark and turtle sightings, schools of surgeonfish, and good macro life in the crevices.',marineLife:[{name:'Green turtle',frequency:'common'},{name:'Reef sharks',frequency:'occasional'},{name:'Surgeonfish',frequency:'very common'},{name:'Moray eel',frequency:'common'}],safetyNotes:['Watch for boat traffic','Moderate current possible — check conditions'],briefing:'Boat entry. Descend to rocks at 10–20m. Circumnavigate the rock formation. Reef sharks patrol the blue edge. Safety stop at 5m. Return to boat.',emergencyContact:'BIMC Hospital Kuta: +62 361 761263',diagramType:'boat' },
  { slug:'mangrove-point',name:'Mangrove Point',area:'Nusa Lembongan',areaSlug:'nusa-lembongan',rank:11,type:'Drift',access:'Boat',minDepth:5,maxDepth:30,avgDepth:18,visibility:'15–25m',temp:'25–28°C',current:'Strong — can be very strong',difficulty:'Advanced',minCert:'Advanced Open Water',bestTime:'Incoming tide',bestSeason:'Apr–Oct',goodFor:['Drift diving','Marine life','Experienced divers'],facilities:['Boat only from Nusa Lembongan'],lat:-8.6789,lng:115.4498,rating:4.6,reviews:67,description:'Mangrove Point in front of the mangrove forest on Nusa Lembongan\'s north coast is one of the richest drift dives in the area. The mangroves provide nutrients that feed one of the healthiest coral reefs around Nusa Penida — ten times richer in marine life than SD Point on a good day. Currents can be multidirectional and unpredictable — experienced drift divers only.',marineLife:[{name:'Bumphead parrotfish',frequency:'common'},{name:'Eagle ray',frequency:'occasional'},{name:'Schooling fish',frequency:'very common'},{name:'Reef sharks',frequency:'common'}],safetyNotes:['Currents can be multidirectional and very strong','Avoid when conditions are marginal — go to SD Point instead','SMB mandatory','Advanced drift diving skills required'],briefing:'Boat entry upstream of point. Descend quickly. Drift along reef with current — coast on one side, blue water on other. Ascend on guide signal. Deploy SMB for boat pick-up.',emergencyContact:'BIMC Hospital Kuta: +62 361 761263',diagramType:'boat' },
  { slug:'amed-wall',name:'Amed Wall',area:'Amed',areaSlug:'amed',rank:12,type:'Wall',access:'Shore',minDepth:3,maxDepth:40,avgDepth:18,visibility:'10–25m',temp:'26–29°C',current:'Mild — good for all levels',difficulty:'All levels',minCert:'Open Water',bestTime:'Morning',bestSeason:'Apr–Nov',goodFor:['Wall diving','Marine life','Photography','All levels'],facilities:['Shore access','Dive centres in Amed'],lat:-8.3456,lng:115.6651,rating:4.5,reviews:53,description:'Amed Wall is a great shore dive accessible for all experience levels. The reef drops from 3m down to 40m with a mix of coral slope and mini wall sections. Known for abundant anthias, beautiful gorgonian fans, pygmy seahorse, frogfish, and reef fish. A reliable, relaxed dive in calm Amed conditions with easy shore access.',marineLife:[{name:'Pygmy seahorse',frequency:'occasional'},{name:'Frogfish',frequency:'occasional'},{name:'Anthias',frequency:'very common'},{name:'Nudibranch',frequency:'common'},{name:'Hawksbill turtle',frequency:'occasional'}],safetyNotes:['Watch depth — wall drops to 40m','Boat traffic near shore entry — ascend on reef','Mild conditions most days'],briefing:'Shore entry from Amed beach. Swim out and descend on the reef slope. Wall sections at 15–30m. Explore at planned depth. Return shallowing up along reef. Safety stop at 5m on reef. Exit to beach.',emergencyContact:'BIMC Hospital Kuta: +62 361 761263',diagramType:'wall' },
  { slug:'pura-jepun',name:'Pura Jepun',area:'Tulamben',areaSlug:'tulamben',rank:13,type:'Reef',access:'Shore',minDepth:3,maxDepth:20,avgDepth:10,visibility:'10–20m',temp:'27–29°C',current:'Mild',difficulty:'Beginner',minCert:'Open Water',bestTime:'Morning or afternoon',bestSeason:'Year round',goodFor:['Beginners','Macro life','Training'],facilities:['Dive centres in Tulamben','Shore access'],lat:-8.2798,lng:115.6015,rating:4.3,reviews:9,description:'A relaxed shallow reef with a unique submerged temple structure colonised by corals. Excellent for beginners and macro photography lovers looking for nudibranchs and critters.',marineLife:[{name:'Nudibranch',frequency:'common'},{name:'Pipefish',frequency:'common'},{name:'Juvenile reef fish',frequency:'very common'}],safetyNotes:['Mild conditions','Boat traffic possible'],briefing:'Shore entry. Shallow reef 3–20m. The submerged temple is at around 8m. Look for nudibranchs and juvenile fish in coral heads. Return to beach.',emergencyContact:'BIMC Hospital Kuta: +62 361 761263',diagramType:'shore' },
  { slug:'secret-bay-gilimanuk',name:'Secret Bay',area:'Gilimanuk',areaSlug:'gilimanuk',rank:14,type:'Muck',access:'Shore',minDepth:2,maxDepth:15,avgDepth:8,visibility:'5–15m',temp:'26–29°C',current:'Mild',difficulty:'All levels',minCert:'Open Water',bestTime:'Morning',bestSeason:'Year round',goodFor:['Macro life','Muck diving','Photography'],facilities:['Shore access','Dive centres in Gilimanuk'],lat:-8.1684,lng:114.4426,rating:4.5,reviews:38,description:'A muck diving paradise hiding extraordinary critters in the sandy shallows of Gilimanuk Bay. Hairy frogfish, ghost pipefish, mantis shrimp, and rare nudibranch make this a macro photographer\'s dream.',marineLife:[{name:'Hairy frogfish',frequency:'occasional'},{name:'Ghost pipefish',frequency:'occasional'},{name:'Mantis shrimp',frequency:'common'},{name:'Blue-ringed octopus',frequency:'rare'}],safetyNotes:['Poor visibility possible','Watch for boat wake'],briefing:'Shore entry from bay. Sandy bottom 2–12m. Move slowly and look at every piece of rubble. Blue-ringed octopus present — never touch.',emergencyContact:'BIMC Hospital Kuta: +62 361 761263',diagramType:'shore' },
  { slug:'seraya-secrets',name:'Seraya Secrets',area:'Tulamben',areaSlug:'tulamben',rank:15,type:'Muck',access:'Shore',minDepth:5,maxDepth:25,avgDepth:12,visibility:'10–20m',temp:'27–29°C',current:'Mild',difficulty:'All levels',minCert:'Open Water',bestTime:'Morning',bestSeason:'Year round',goodFor:['Macro life','Muck diving','Photography'],facilities:['Shore access','Dive centres nearby'],lat:-8.3102,lng:115.5901,rating:4.4,reviews:29,description:'Bali\'s premier muck diving site on black volcanic sand between Tulamben and Amed. The slope hides mimic octopus, flamboyant cuttlefish, blue-ringed octopus, rhinopias scorpionfish, and ghost pipefish. World-class macro photography day and night.',marineLife:[{name:'Mimic octopus',frequency:'occasional'},{name:'Flamboyant cuttlefish',frequency:'occasional'},{name:'Blue-ringed octopus',frequency:'rare'},{name:'Rhinopias scorpionfish',frequency:'rare'}],safetyNotes:['Blue-ringed octopus — do not touch','Move very slowly to avoid disturbing critters'],briefing:'Shore entry. Black sand slope descending to 25m. Move slowly. Look at everything. Good buoyancy essential. Return to beach.',emergencyContact:'BIMC Hospital Kuta: +62 361 761263',diagramType:'shore' },
  { slug:'drift-dive-nusa-penida',name:'Drift Dive Nusa Penida',area:'Nusa Penida',areaSlug:'nusa-penida',rank:16,type:'Drift',access:'Boat',minDepth:5,maxDepth:35,avgDepth:22,visibility:'15–30m',temp:'22–27°C',current:'Very strong',difficulty:'Advanced',minCert:'Advanced Open Water',bestTime:'Slack tide',bestSeason:'May–Sep',goodFor:['Drift diving','Big fish','Experienced divers'],facilities:['Boat only'],lat:-8.7542,lng:115.5198,rating:4.6,reviews:44,description:'One of the most thrilling drift dives in Southeast Asia. The ripping currents of the Lombok Strait push divers past schooling hammerheads, oceanic mantas, and sunfish past Nusa Penida\'s north coast sites.',marineLife:[{name:'Hammerhead shark',frequency:'seasonal'},{name:'Oceanic manta',frequency:'seasonal'},{name:'Dogtooth tuna',frequency:'common'}],safetyNotes:['Very strong current — experienced drift divers only','SMB mandatory'],briefing:'Boat entry at slack tide. Descend quickly. Stay at planned depth. Deploy SMB early. Pick-up by boat only.',emergencyContact:'Nusa Penida Health Clinic: +62 366 5598001',diagramType:'boat' },
  { slug:'menjangan-wall',name:'Menjangan Wall',area:'Menjangan',areaSlug:'menjangan',rank:17,type:'Wall',access:'Boat',minDepth:3,maxDepth:40,avgDepth:20,visibility:'20–40m',temp:'27–30°C',current:'Mild',difficulty:'Intermediate',minCert:'Open Water',bestTime:'Morning',bestSeason:'Apr–Nov',goodFor:['Wall diving','Marine life','Photography'],facilities:['Boat only','Menjangan Island National Park — permit required'],lat:-8.1068,lng:114.5079,rating:4.8,reviews:71,description:'Often cited as Bali\'s best wall dive. Menjangan Island in West Bali National Park has crystal-clear water and a pristine vertical wall draped in black coral trees, sea fans in every colour, and dense soft corals. One of the most visually spectacular walls in all of Indonesia.',marineLife:[{name:'Black coral trees',frequency:'very common'},{name:'Sea fans',frequency:'very common'},{name:'Reef sharks',frequency:'occasional'},{name:'Napoleon wrasse',frequency:'occasional'}],safetyNotes:['National Park — no collecting or touching coral','National Park permit required — arrange before diving','Boat only access'],briefing:'Boat entry from Menjangan Island. Descend to wall edge. Drift gently along the wall face. Ascend slowly. National Park permit must be carried by guide.',emergencyContact:'BIMC Hospital Kuta: +62 361 761263',diagramType:'wall' },
  { slug:'pemuteran-reef',name:'Pemuteran Biorock',area:'Pemuteran',areaSlug:'pemuteran',rank:18,type:'Reef',access:'Shore',minDepth:3,maxDepth:18,avgDepth:10,visibility:'10–20m',temp:'27–30°C',current:'Mild',difficulty:'Beginner',minCert:'Open Water',bestTime:'Morning',bestSeason:'Year round',goodFor:['Beginners','Training','Biorock reef conservation'],facilities:['Shore access','Dive centres in Pemuteran'],lat:-8.1156,lng:114.6324,rating:4.3,reviews:34,description:'Home to the world\'s largest Biorock reef restoration project. Low-voltage electrical current accelerates coral growth on artificial steel structures now colonised by thriving corals and clownfish. An inspiring and easy dive for all levels with great snorkelling.',marineLife:[{name:'Clownfish',frequency:'very common'},{name:'Coral colonies',frequency:'very common'},{name:'Reef fish',frequency:'very common'}],safetyNotes:['Do not touch the Biorock structures','Very mild conditions'],briefing:'Shore entry. Sandy bottom to Biorock structures at 5–15m. Observe coral restoration. Do not touch. Return to shore.',emergencyContact:'BIMC Hospital Kuta: +62 361 761263',diagramType:'shore' },
  { slug:'nusa-lembongan-reef',name:'Nusa Lembongan Reef',area:'Nusa Lembongan',areaSlug:'nusa-lembongan',rank:19,type:'Reef',access:'Boat',minDepth:5,maxDepth:25,avgDepth:14,visibility:'15–25m',temp:'25–28°C',current:'Moderate',difficulty:'Intermediate',minCert:'Open Water',bestTime:'Morning',bestSeason:'Apr–Oct',goodFor:['Reef diving','Marine life'],facilities:['Dive centres on Nusa Lembongan'],lat:-8.6923,lng:115.4537,rating:4.4,reviews:47,description:'A classic Lembongan reef with healthy coral coverage and reliable fish life. A great base dive in calm conditions between the more challenging Nusa Penida sites. Turtles, moray eels and reef fish are reliable.',marineLife:[{name:'Sea turtle',frequency:'common'},{name:'Reef fish',frequency:'very common'},{name:'Moray eel',frequency:'common'}],safetyNotes:['Moderate current','Stay with guide'],briefing:'Boat entry. Descend to reef at 10–20m. Follow the coral slope with guide. Return to boat on signal. SMB.',emergencyContact:'BIMC Hospital Kuta: +62 361 761263',diagramType:'boat' },
  { slug:'bias-tugel',name:'Bias Tugel',area:'Padang Bai',areaSlug:'padang-bai',rank:20,type:'Reef',access:'Shore',minDepth:5,maxDepth:20,avgDepth:12,visibility:'10–20m',temp:'27–29°C',current:'Mild',difficulty:'Beginner',minCert:'Open Water',bestTime:'Morning',bestSeason:'Year round',goodFor:['Beginners','Marine life','Snorkelling'],facilities:['Shore access — short jungle walk','Small beach warungs'],lat:-8.5401,lng:115.5043,rating:4.2,reviews:28,description:'A hidden gem beach accessed by a short walk through the jungle from Padang Bai. Lovely shallow reef just offshore with good reef fish, coral bommies, and the occasional reef shark in deeper water. Excellent for strong snorkellers too.',marineLife:[{name:'Parrotfish',frequency:'very common'},{name:'Coral bommies',frequency:'very common'},{name:'Reef shark',frequency:'occasional'}],safetyNotes:['Boat traffic near bay entrance','Use a dive flag if snorkelling'],briefing:'Shore entry from Bias Tugel beach. Reef slope to 15–18m. Explore bommies. Return toward shore. Safety stop at 5m. Exit at beach.',emergencyContact:'BIMC Hospital Kuta: +62 361 761263',diagramType:'shore' },
  { slug:'japanese-wreck-amed',name:'Japanese Wreck (Amed)',area:'Amed',areaSlug:'amed',rank:21,type:'Wreck',access:'Shore',minDepth:6,maxDepth:12,avgDepth:9,visibility:'10–20m',temp:'26–29°C',current:'Mild — can be tricky near Lombok Strait',difficulty:'All levels',minCert:'Open Water',bestTime:'Morning',bestSeason:'Apr–Nov',goodFor:['Wreck diving','Photography','Macro life','Snorkelling','All levels'],facilities:['Shore access from Lipah Bay (Banyuning beach)','Dive centres in Amed — 20 min drive'],lat:-8.3534,lng:115.6724,rating:4.5,reviews:89,description:'Located in the calm bay of Lipah (Banyuning), about 7km from Jemeluk, the Japanese Wreck (believed to be the Kikukawa Maru, a WWII cargo ship) lies just 15m from the beach in only 6–12m of water. The ~20m long steel hull sits upright on a sandy slope encrusted in gorgeous gorgonians, sponges, and black coral. A rich surrounding reef with macro critters in the sand makes this a full dive. Popular for snorkelling due to its shallow depth. Occasional current from the Lombok Strait.',marineLife:[{name:'Gorgonian sea fans',frequency:'very common'},{name:'Nudibranch',frequency:'very common'},{name:'Ghost pipefish',frequency:'occasional'},{name:'Pygmy seahorse',frequency:'occasional'},{name:'Leaf scorpionfish',frequency:'occasional'},{name:'Reef fish',frequency:'very common'}],safetyNotes:['Close to Lombok Strait — current can be tricky and unpredictable','Listen to your guide','Very shallow — excellent buoyancy required to avoid damaging coral'],briefing:'Shore entry from Lipah Bay beach — wreck is just 15m from shore. Wade in and descend. Wreck at 6–12m, upright on sand. Explore hull, then surrounding reef and sandy slope for macro life. Safety stop at 5m in shallows. Exit to beach.',emergencyContact:'BIMC Hospital Kuta: +62 361 761263',diagramType:'wreck' },
  { slug:'batu-bulan',name:'Batu Bulan',area:'Amed',areaSlug:'amed',rank:22,type:'Reef',access:'Shore',minDepth:3,maxDepth:35,avgDepth:18,visibility:'10–25m',temp:'26–29°C',current:'Mild to moderate',difficulty:'Intermediate',minCert:'Open Water',bestTime:'Morning',bestSeason:'Apr–Nov',goodFor:['Reef diving','Marine life','Photography','All levels'],facilities:['Shore access','Dive centres in Amed'],lat:-8.3389,lng:115.6612,rating:4.4,reviews:52,description:'Batu Bulan — Moon Rock — is a dramatic underwater pinnacle rising from 35m to just 3m. Densely colonised by corals, it attracts big schools of fusiliers, reef sharks, and the occasional bumphead parrotfish. A memorable pinnacle dive in calm Amed conditions.',marineLife:[{name:'Fusilier school',frequency:'very common'},{name:'Whitetip reef shark',frequency:'common'},{name:'Bumphead parrotfish',frequency:'occasional'},{name:'Nudibranch',frequency:'common'}],safetyNotes:['Watch depth on drop-off sides','Current can pick up mid-day'],briefing:'Shore entry. Swim out to pinnacle. Circumnavigate from 5m down to planned depth. Return to shallows for safety stop. Exit to beach.',emergencyContact:'BIMC Hospital Kuta: +62 361 761263',diagramType:'boat' },
  { slug:'the-pyramids-amed',name:'The Pyramids',area:'Amed',areaSlug:'amed',rank:23,type:'Reef',access:'Shore',minDepth:5,maxDepth:30,avgDepth:15,visibility:'10–25m',temp:'26–29°C',current:'Mild — can drift',difficulty:'All levels',minCert:'Open Water',bestTime:'Morning',bestSeason:'Year round',goodFor:['All levels','Snorkelling','Reef diving','Photography','Macro'],facilities:['Shore access or short jukung ride from Jemeluk','Dive centres in Amed and Jemeluk'],lat:-8.3428,lng:115.6634,rating:4.6,reviews:74,description:'Over 50 concrete pyramid-shaped artificial reef structures placed on the sandy bottom in Jemeluk Bay at depths of 5–30m. Built after the 1998 El Niño coral bleaching event, they are now magnificently colonised by soft corals, sponges, and gorgonians. Garden eels in the sand, blue-spotted stingrays, ghost pipefish, pygmy seahorse, leaf scorpionfish, and titan triggerfish are regular finds. Can be dived as a gentle drift from west to east.',marineLife:[{name:'Garden eels',frequency:'very common'},{name:'Blue-spotted stingray',frequency:'common'},{name:'Ghost pipefish',frequency:'occasional'},{name:'Pygmy seahorse',frequency:'occasional'},{name:'Titan triggerfish',frequency:'common'},{name:'Clownfish',frequency:'very common'}],safetyNotes:['Titan triggerfish can be aggressive near nests — give space','Stay off pyramid structures — fragile coral growth','Current from west to east — plan exit accordingly'],briefing:'Shore entry or jukung drop on west end of pyramids. Descend to sandy bottom. Drift gently eastward among the pyramid structures at 5–25m. Look in sand for garden eels and rays. Ascend and exit on east side or return against mild current.',emergencyContact:'BIMC Hospital Kuta: +62 361 761263',diagramType:'shore' },
  { slug:'jemeluk-bay-bali',name:'Jemeluk Bay',area:'Amed',areaSlug:'amed',rank:24,type:'Reef',access:'Shore',minDepth:3,maxDepth:40,avgDepth:14,visibility:'15–25m',temp:'26–29°C',current:'Mild — protected bay, no current most days',difficulty:'All levels',minCert:'Open Water',bestTime:'Morning',bestSeason:'Apr–Nov',goodFor:['All levels','Beginners','Snorkelling','Coral garden','Night diving','Photography'],facilities:['Shore access from Jemeluk beach','Multiple dive centres in Jemeluk'],lat:-8.3298,lng:115.6563,rating:4.7,reviews:112,description:'Jemeluk Bay is the centrepiece of Amed diving — a wide, sheltered bay devoid of current most days, making it perfect for all levels. The shallow coral plateau hosts the Pyramids on one side and the wall on the other. Coral bommies covered in gorgonians provide photographic subjects, while the wall outside the bay drops to 35m+ with whitetip sharks, napoleons, jacks, and butterfly fish. The bay is also ideal for night diving.',marineLife:[{name:'Gorgonian bommies',frequency:'very common'},{name:'Barracuda',frequency:'common'},{name:'Whitetip reef shark',frequency:'common'},{name:'Napoleon wrasse',frequency:'occasional'},{name:'Butterfly fish',frequency:'very common'}],safetyNotes:['Boat traffic on surface — ascend on reef, not open water','Wall outside bay drops to 40m — watch depth','Protected bay in normal conditions'],briefing:'Shore entry from Jemeluk beach. Descend on sandy slope to coral bommies and reef. Explore inside bay at 5–15m. For wall: exit bay and descend along wall to planned depth. Return inside bay to ascend. Safety stop at 5m. Exit to beach.',emergencyContact:'BIMC Hospital Kuta: +62 361 761263',diagramType:'wall' },
  { slug:'jemeluk-wall',name:'Jemeluk Wall',area:'Amed',areaSlug:'amed',rank:25,type:'Wall',access:'Boat',minDepth:10,maxDepth:40,avgDepth:22,visibility:'10–25m',temp:'26–29°C',current:'Mild to moderate',difficulty:'Intermediate',minCert:'Open Water',bestTime:'Morning',bestSeason:'Apr–Nov',goodFor:['Wall diving','Marine life','Photography','Intermediate divers'],facilities:['Short jukung ride (5 min) from Jemeluk beach','Shore also possible'],lat:-8.3285,lng:115.6548,rating:4.8,reviews:96,description:'The outer wall of Jemeluk Bay drops vertically from 10m to over 80m, rich with colourful gorgonians, deep red barrel sponges, and hundreds of anthias. Best accessed by a 5-minute jukung ride to the wall face. Requires great buoyancy to avoid damaging the fans in current. Whitetip sharks patrol below, and occasional hammerheads are reported in season.',marineLife:[{name:'Gorgonian sea fans',frequency:'very common'},{name:'Barrel sponges',frequency:'very common'},{name:'Anthias',frequency:'very common'},{name:'Whitetip reef shark',frequency:'common'},{name:'Scorpionfish',frequency:'common'}],safetyNotes:['Wall drops past 80m — strict depth discipline','Good buoyancy essential — do not fin into fans','Current can carry you into structure for photographers'],briefing:'Jukung drop at wall. Descend along wall face. Maximum depth 30–35m recommended. Follow wall — gorgonians become larger with depth. Turn on guide signal. Ascend along wall. Safety stop at 5m. Pick up by jukung.',emergencyContact:'BIMC Hospital Kuta: +62 361 761263',diagramType:'wall' },
  { slug:'deep-blue-amed-v1',name:'Deep Blue',area:'Amed',areaSlug:'amed',rank:26,type:'Drift',access:'Boat',minDepth:5,maxDepth:40,avgDepth:25,visibility:'15–30m',temp:'25–28°C',current:'Moderate to strong — horizontal drift',difficulty:'Advanced',minCert:'Advanced Open Water',bestTime:'Early morning',bestSeason:'Apr–Nov',goodFor:['Advanced divers','Drift diving','Pelagics','Big fish'],facilities:['15 min jukung from Amed/Jemeluk'],lat:-8.3156,lng:115.6489,rating:4.7,reviews:61,description:'Deep Blue is a 15-minute jukung ride from Amed — a challenging drift dive for advanced divers. The dive starts in a shallow bay with coral bommies and sea fans, then drops into the current at around 30m where the horizontal drift carries divers past schools of batfish, snappers, Napoleon wrasses, giant trevallies, and barracuda. Sharks and turtles are common. No up or down current — a relaxed but exciting drift at depth.',marineLife:[{name:'Batfish',frequency:'common'},{name:'Napoleon wrasse',frequency:'common'},{name:'Barracuda',frequency:'common'},{name:'Giant trevally',frequency:'common'},{name:'Reef shark',frequency:'common'},{name:'Hawksbill turtle',frequency:'occasional'}],safetyNotes:['Deep drift dive — strict NDL management required','Advanced divers only','SMB mandatory for boat pick-up','Remote location'],briefing:'Jukung drop. Start in shallow bay with coral bommies. Move to deeper section at 25–30m where current picks up. Drift horizontally — relax and enjoy the show. Schools of fish all around. Guide signals ascent. Deploy SMB. Jukung pick-up.',emergencyContact:'BIMC Hospital Kuta: +62 361 761263',diagramType:'boat' },
]
